function getShift(timeString) {
    const hours = parseInt(timeString.split(':')[0], 10);
    if (hours >= 6 && hours < 14) {
        return 'A';
    } else if (hours >= 14 && hours < 22) {
        return 'B';
    } else {
        return 'C';
    }
}

const targetKey = `${args.field_data_key}`;
const time = e.args[0];
const shift = getShift(time);
e.data[targetKey] = shift;

set_upload_url.body:
