load_bogie_name_data.body:
const [searchValue, loadCallback, currentDataLength] = e.args;

// If already cached, use it
if (e.data.bogie_dropdown_options) {
    const assemblyNames = Object.keys(e.data.bogie_dropdown_options);
    const preparedData = assemblyNames.map(name => ({ value: name, label: name }));
    if (typeof loadCallback === 'function') loadCallback(preparedData);
    return;
}

let savedToken = localStorage.getItem('dlms_auth_token');

fetch('https://dlms-api-stage.iotnp.com/api/v1/templates/dispatch_operational/dropdown/v2', {
    method: 'POST',
    headers: {
        'accept': 'application/json',
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${savedToken}`
    },
    body: JSON.stringify({
        fields: ['data.main.data'],
        search_fields: [],
        search: '',
        status: 'pending',
        limit: 100
    })
})
.then(res => res.json())
.then(response => {
    const items = response.data || [];
    const result = {};

    items.forEach(item => {
        const mainData = item['data.main.data'];
        if (!mainData) return;
        const mapArr = mainData['parent_data__batch__assembly_bogieid_bogieno_map'];
        if (!Array.isArray(mapArr) || mapArr.length === 0) return;

        mapArr.forEach(row => {
            const assembly = row.assembly || '';
            const bogieNo = row.bogie_no || '';
            const bogieId = row.bogie_id || '';
            const dmNo = row.dm_no || '';
            const castings = (row.castings || []).map(c => `${c.name}: ${c.serials}`);

            if (!result[assembly]) result[assembly] = {};
            if (!result[assembly][bogieNo]) {
                result[assembly][bogieNo] = {
                    bogie_id: new Set(),
                    dm_no: new Set(),
                    list_of_castings: new Set()
                };
            }
            if (bogieId) result[assembly][bogieNo].bogie_id.add(bogieId);
            if (dmNo) result[assembly][bogieNo].dm_no.add(dmNo);
            castings.forEach(c => result[assembly][bogieNo].list_of_castings.add(c));
        });
    });

    // Convert sets to semicolon-joined strings
    const finalResult = {};
    Object.keys(result).forEach(assembly => {
        finalResult[assembly] = {};
        Object.keys(result[assembly]).forEach(bogieNo => {
            const entry = result[assembly][bogieNo];
            finalResult[assembly][bogieNo] = {
                bogie_id: [...entry.bogie_id].join('; '),
                dm_no: [...entry.dm_no].join('; '),
                list_of_castings: [...entry.list_of_castings].join('; ')
            };
        });
    });

    e.data.bogie_dropdown_options = finalResult;

    const assemblyNames = Object.keys(finalResult);
    const preparedData = assemblyNames.map(name => ({ value: name, label: name }));
    if (typeof loadCallback === 'function') loadCallback(preparedData);
})
.catch(err => {
    console.error('load_bogie_name_data fetch error:', err);
    if (typeof loadCallback === 'function') loadCallback([]);
});

