on_bogie_no_select.body:
const rowIndex = args.row_index;
const selectedBogieNo = e.args[0];

// Guard: check if this bogie_no is already selected in another row
if (selectedBogieNo) {
    for (let i = 0; i < 20; i++) {
        if (i === rowIndex) continue;
        const existing = e.data['bogie__' + i + '__bogie_no'];
        if (existing && existing === selectedBogieNo) {
            e.data['bogie__' + rowIndex + '__bogie_no'] = '';
            const node = e.store?.form?.componentTree?.findByKey('bogie__' + rowIndex + '__bogie_no');
            if (node && node.store) node.store.value = '';
            if (e.store?.form) {
                e.store.form.errors = e.store.form.errors || {};
                e.store.form.errors['bogie__' + rowIndex + '__bogie_no'] = 'Bogie No. "' + selectedBogieNo + '" is already used in row ' + (i + 1);
            }
            return;
        }
    }
}

// Clear any previous error
if (e.store?.form?.errors) {
    delete e.store.form.errors['bogie__' + rowIndex + '__bogie_no'];
}

const selectedAssembly = e.data['bogie__' + rowIndex + '__bogie_name'];
const options = e.data.bogie_dropdown_options;

if (selectedAssembly && options && options[selectedAssembly] && options[selectedAssembly][selectedBogieNo]) {
    const match = options[selectedAssembly][selectedBogieNo];
    e.data['bogie__' + rowIndex + '__bogie_id'] = match.bogie_id || '';
    e.data['bogie__' + rowIndex + '__dm_no'] = match.dm_no || '';
    e.data['bogie__' + rowIndex + '__castings'] = match.list_of_castings || '';

    const fields = [
        { key: 'bogie_id', val: match.bogie_id },
        { key: 'dm_no', val: match.dm_no },
        { key: 'castings', val: match.list_of_castings }
    ];
    fields.forEach(f => {
        const node = e.store?.form?.componentTree?.findByKey('bogie__' + rowIndex + '__' + f.key);
        if (node && node.store) node.store.value = f.val || '';
    });
}

