formValidator:
const errors = {};
for (let i = 0; i < 20; i++) {
    const nameVal = formData['bogie__' + i + '__bogie_name'];
    const noVal = formData['bogie__' + i + '__bogie_no'];
    // If bogie_name is selected but bogie_no is not
    if (nameVal && nameVal !== '' && (!noVal || noVal === '')) {
        errors['bogie__' + i + '__bogie_no'] = 'Bogie No. is required when Bogie Name is selected';
    }
    // Check for duplicate bogie_no
    if (noVal && noVal !== '') {
        for (let j = 0; j < i; j++) {
            const otherVal = formData['bogie__' + j + '__bogie_no'];
            if (otherVal && otherVal === noVal) {
                errors['bogie__' + i + '__bogie_no'] = 'Bogie No. "' + noVal + '" is already used in row ' + (j + 1);
                break;
            }
        }
    }
}
return Object.keys(errors).length > 0 ? errors : undefined;
